                                    {/* Auto-filled Author Display */}
                                    {selectedBookDetails && (
                                        <p className="text-xs text-brand-secondary mt-2 px-1 flex items-center gap-1">
                                            <User size={12} />
                                            Autor: <span className="font-semibold text-brand-primary line-clamp-1">{selectedBookDetails.author}</span>
